-- --------------------------------------------------------------------------- -- 9. Legacy backfill: media_assets for existing spot_images (spots bucket) -- --------------------------------------------------------------------------- insert into public.media_assets (   owner_id,   kind,   status,   approved_bucket,   approved_path,   mime_type ) select s.user_id, 'spot_image', 'legacy_unmoderated', 'spots', si.storage_path, 'image/jpeg' from public.spot_images si join public.spots s on s.id = si.spot_id where si.media_asset_id is null   and si.storage_path is not null   and trim(si.storage_path) <> ''   and not exists (     select 1     from public.media_assets ma     where ma.approved_bucket = 'spots'       and ma.approved_path = si.storage_path       and ma.owner_id = s.user_id       and ma.kind = 'spot_image'   );  update public.spot_images si set media_asset_id = ma.id from public.media_assets ma, public.spots s where si.spot_id = s.id   and ma.owner_id = s.user_id   and ma.approved_bucket = 'spots'   and ma.approved_path = si.storage_path   and ma.kind = 'spot_image'   and ma.status = 'legacy_unmoderated'   and si.media_asset_id is null;  -- ---------------------------------------------------------------------------